/**
 * Indexer service for building and updating indexes
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import type { MdSection } from '../core/types.js'
import { parse } from '../parser/parser.js'
import {
  computeHash,
  createEmptyDocumentIndex,
  createEmptyLinkIndex,
  createEmptySectionIndex,
  createStorage,
  initializeIndex,
  loadDocumentIndex,
  loadLinkIndex,
  saveDocumentIndex,
  saveLinkIndex,
  saveSectionIndex,
} from './storage.js'
import type {
  DocumentEntry,
  DocumentIndex,
  IndexBuildError,
  IndexResult,
  SectionEntry,
} from './types.js'

// ============================================================================
// File Discovery
// ============================================================================

const isMarkdownFile = (filename: string): boolean =>
  filename.endsWith('.md') || filename.endsWith('.mdx')

const shouldExclude = (
  filePath: string,
  exclude: readonly string[],
): boolean => {
  const normalized = filePath.toLowerCase()
  for (const pattern of exclude) {
    if (
      pattern.includes('node_modules') &&
      normalized.includes('node_modules')
    ) {
      return true
    }
    if (pattern.startsWith('**/.*') && normalized.includes('/.')) {
      return true
    }
  }
  return false
}

const walkDirectory = async (
  dir: string,
  exclude: readonly string[],
): Promise<string[]> => {
  const files: string[] = []
  const entries = await fs.readdir(dir, { withFileTypes: true })

  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name)

    if (entry.name.startsWith('.') || entry.name === 'node_modules') {
      continue
    }

    if (shouldExclude(fullPath, exclude)) {
      continue
    }

    if (entry.isDirectory()) {
      const subFiles = await walkDirectory(fullPath, exclude)
      files.push(...subFiles)
    } else if (entry.isFile() && isMarkdownFile(entry.name)) {
      files.push(fullPath)
    }
  }

  return files
}

// ============================================================================
// Section Flattening
// ============================================================================

const flattenSections = (
  sections: readonly MdSection[],
  docId: string,
  docPath: string,
): SectionEntry[] => {
  const result: SectionEntry[] = []

  const traverse = (section: MdSection): void => {
    result.push({
      id: section.id,
      documentId: docId,
      documentPath: docPath,
      heading: section.heading,
      level: section.level,
      startLine: section.startLine,
      endLine: section.endLine,
      tokenCount: section.metadata.tokenCount,
      hasCode: section.metadata.hasCode,
      hasList: section.metadata.hasList,
      hasTable: section.metadata.hasTable,
    })

    for (const child of section.children) {
      traverse(child)
    }
  }

  for (const section of sections) {
    traverse(section)
  }

  return result
}

// ============================================================================
// Link Resolution
// ============================================================================

const resolveInternalLink = (
  href: string,
  fromPath: string,
  rootPath: string,
): string | null => {
  if (href.startsWith('#')) {
    return fromPath
  }

  if (href.startsWith('http://') || href.startsWith('https://')) {
    return null
  }

  const linkPath = href.split('#')[0] ?? ''
  if (!linkPath) return null

  const fromDir = path.dirname(fromPath)
  const resolved = path.resolve(fromDir, linkPath)

  if (!resolved.startsWith(rootPath)) {
    return null
  }

  return path.relative(rootPath, resolved)
}

// ============================================================================
// Index Building
// ============================================================================

export interface IndexOptions {
  readonly force?: boolean
  readonly exclude?: readonly string[]
}

export const buildIndex = (
  rootPath: string,
  options: IndexOptions = {},
): Effect.Effect<IndexResult, Error> =>
  Effect.gen(function* () {
    const startTime = Date.now()
    const storage = createStorage(rootPath)
    const errors: IndexBuildError[] = []

    // Initialize storage
    yield* initializeIndex(storage)

    // Load existing indexes or create empty ones
    const existingDocIndex = yield* loadDocumentIndex(storage)
    const docIndex: DocumentIndex =
      options.force || !existingDocIndex
        ? createEmptyDocumentIndex(storage.rootPath)
        : existingDocIndex

    const sectionIndex = createEmptySectionIndex()
    const linkIndex = createEmptyLinkIndex()

    // Discover files
    const exclude = options.exclude ?? ['**/node_modules/**', '**/.*/**']
    const files = yield* Effect.tryPromise({
      try: () => walkDirectory(storage.rootPath, exclude),
      catch: (e) => new Error(`Failed to walk directory: ${e}`),
    })

    // Process each file
    let documentsIndexed = 0
    let sectionsIndexed = 0
    let linksIndexed = 0

    const mutableDocuments: Record<string, DocumentEntry> = {
      ...docIndex.documents,
    }
    const mutableSections: Record<string, SectionEntry> = {}
    const mutableByHeading: Record<string, string[]> = {}
    const mutableByDocument: Record<string, string[]> = {}
    const mutableForward: Record<string, string[]> = {}
    const mutableBackward: Record<string, string[]> = {}
    const brokenLinks: string[] = []

    for (const filePath of files) {
      const relativePath = path.relative(storage.rootPath, filePath)

      try {
        // Read file content and stats
        const [content, stats] = yield* Effect.promise(() =>
          Promise.all([fs.readFile(filePath, 'utf-8'), fs.stat(filePath)]),
        )

        const hash = computeHash(content)
        const existingEntry = mutableDocuments[relativePath]

        // Skip if unchanged
        if (
          !options.force &&
          existingEntry &&
          existingEntry.hash === hash &&
          existingEntry.mtime === stats.mtime.getTime()
        ) {
          continue
        }

        // Parse document
        const doc = yield* parse(content, {
          path: relativePath,
          lastModified: stats.mtime,
        }).pipe(
          Effect.mapError(
            (e) => new Error(`Parse error in ${relativePath}: ${e.message}`),
          ),
        )

        // Update document index
        mutableDocuments[relativePath] = {
          id: doc.id,
          path: relativePath,
          title: doc.title,
          mtime: stats.mtime.getTime(),
          hash,
          tokenCount: doc.metadata.tokenCount,
          sectionCount: doc.metadata.headingCount,
        }

        documentsIndexed++

        // Update section index
        const sections = flattenSections(doc.sections, doc.id, relativePath)
        mutableByDocument[doc.id] = []

        for (const section of sections) {
          mutableSections[section.id] = section
          mutableByDocument[doc.id]?.push(section.id)

          // Index by heading
          const headingKey = section.heading.toLowerCase()
          if (!mutableByHeading[headingKey]) {
            mutableByHeading[headingKey] = []
          }
          mutableByHeading[headingKey]?.push(section.id)

          sectionsIndexed++
        }

        // Update link index
        const internalLinks = doc.links.filter((l) => l.type === 'internal')
        const outgoingLinks: string[] = []

        for (const link of internalLinks) {
          const target = resolveInternalLink(
            link.href,
            filePath,
            storage.rootPath,
          )

          if (target) {
            outgoingLinks.push(target)

            // Add to backward links
            if (!mutableBackward[target]) {
              mutableBackward[target] = []
            }
            if (!mutableBackward[target]?.includes(relativePath)) {
              mutableBackward[target]?.push(relativePath)
            }

            linksIndexed++
          }
        }

        mutableForward[relativePath] = outgoingLinks
      } catch (error) {
        errors.push({
          path: relativePath,
          message: error instanceof Error ? error.message : String(error),
        })
      }
    }

    // Check for broken links
    for (const [_from, targets] of Object.entries(mutableForward)) {
      for (const target of targets) {
        if (!mutableDocuments[target] && !brokenLinks.includes(target)) {
          brokenLinks.push(target)
        }
      }
    }

    // Save indexes
    yield* saveDocumentIndex(storage, {
      version: docIndex.version,
      rootPath: storage.rootPath,
      documents: mutableDocuments,
    })

    yield* saveSectionIndex(storage, {
      version: sectionIndex.version,
      sections: mutableSections,
      byHeading: mutableByHeading,
      byDocument: mutableByDocument,
    })

    yield* saveLinkIndex(storage, {
      version: linkIndex.version,
      forward: mutableForward,
      backward: mutableBackward,
      broken: brokenLinks,
    })

    const duration = Date.now() - startTime

    return {
      documentsIndexed,
      sectionsIndexed,
      linksIndexed,
      duration,
      errors,
    }
  })

// ============================================================================
// Link Queries
// ============================================================================

export const getOutgoingLinks = (
  rootPath: string,
  filePath: string,
): Effect.Effect<readonly string[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)
    const linkIndex = yield* loadLinkIndex(storage)

    if (!linkIndex) {
      return []
    }

    const relativePath = path.relative(storage.rootPath, path.resolve(filePath))
    return linkIndex.forward[relativePath] ?? []
  })

export const getIncomingLinks = (
  rootPath: string,
  filePath: string,
): Effect.Effect<readonly string[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)
    const linkIndex = yield* loadLinkIndex(storage)

    if (!linkIndex) {
      return []
    }

    const relativePath = path.relative(storage.rootPath, path.resolve(filePath))
    return linkIndex.backward[relativePath] ?? []
  })

export const getBrokenLinks = (
  rootPath: string,
): Effect.Effect<readonly string[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)
    const linkIndex = yield* loadLinkIndex(storage)

    if (!linkIndex) {
      return []
    }

    return linkIndex.broken
  })

/**
 * INDEX Command
 *
 * Index markdown files for fast searching.
 */

import * as path from 'node:path'
import { Args, Command, Options } from '@effect/cli'
import { Console, Effect } from 'effect'
import { buildEmbeddings } from '../../embeddings/semantic-search.js'
import { buildIndex } from '../../index/indexer.js'
import { watchDirectory } from '../../index/watcher.js'
import { forceOption, jsonOption, prettyOption } from '../options.js'
import { formatJson } from '../utils.js'

export const indexCommand = Command.make(
  'index',
  {
    path: Args.directory({ name: 'path' }).pipe(
      Args.withDescription('Directory to index'),
      Args.withDefault('.'),
    ),
    embed: Options.boolean('embed').pipe(
      Options.withAlias('e'),
      Options.withDescription('Also build semantic embeddings'),
      Options.withDefault(false),
    ),
    watch: Options.boolean('watch').pipe(
      Options.withAlias('w'),
      Options.withDescription('Watch for changes'),
      Options.withDefault(false),
    ),
    force: forceOption,
    json: jsonOption,
    pretty: prettyOption,
  },
  ({ path: dirPath, embed, watch: watchMode, force, json, pretty }) =>
    Effect.gen(function* () {
      const resolvedDir = path.resolve(dirPath)

      if (watchMode) {
        yield* Console.log(`Watching ${resolvedDir} for changes...`)
        yield* Console.log('Press Ctrl+C to stop.')
        yield* Console.log('')

        const watcher = yield* watchDirectory(resolvedDir, {
          force,
          onIndex: (result) => {
            if (json) {
              console.log(formatJson(result, pretty))
            } else {
              console.log(
                `Re-indexed ${result.documentsIndexed} documents (${result.duration}ms)`,
              )
            }
          },
          onError: (error) => {
            console.error(`Watch error: ${error.message}`)
          },
        })

        yield* Effect.async<never, never>(() => {
          process.on('SIGINT', () => {
            watcher.stop()
            console.log('\nStopped watching.')
            process.exit(0)
          })
        })
      } else {
        yield* Console.log(`Indexing ${resolvedDir}...`)

        const result = yield* buildIndex(resolvedDir, { force })

        if (!json) {
          yield* Console.log('')
          yield* Console.log(`Indexed ${result.documentsIndexed} documents`)
          yield* Console.log(`  Sections: ${result.sectionsIndexed}`)
          yield* Console.log(`  Links: ${result.linksIndexed}`)
          yield* Console.log(`  Duration: ${result.duration}ms`)

          if (result.errors.length > 0) {
            yield* Console.log('')
            yield* Console.log(`Errors (${result.errors.length}):`)
            for (const error of result.errors) {
              yield* Console.log(`  ${error.path}: ${error.message}`)
            }
          }
        }

        // Build embeddings if requested
        if (embed) {
          yield* Console.log('')
          yield* Console.log('Building embeddings...')

          const embedResult = yield* buildEmbeddings(resolvedDir, { force })

          if (!json) {
            yield* Console.log(
              `Embedded ${embedResult.sectionsEmbedded} sections`,
            )
            yield* Console.log(`  Tokens used: ${embedResult.tokensUsed}`)
            yield* Console.log(`  Cost: $${embedResult.cost.toFixed(6)}`)
            yield* Console.log(`  Duration: ${embedResult.duration}ms`)
          }
        }

        if (json) {
          yield* Console.log(formatJson(result, pretty))
        }
      }
    }),
).pipe(Command.withDescription('Index markdown files'))

/**
 * Index storage operations
 */

import * as crypto from 'node:crypto'
import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'

import type {
  DocumentIndex,
  IndexConfig,
  LinkIndex,
  SectionIndex,
} from './types.js'
import { getIndexPaths, INDEX_VERSION } from './types.js'

// ============================================================================
// File System Helpers
// ============================================================================

const ensureDir = (dirPath: string): Effect.Effect<void, Error> =>
  Effect.tryPromise({
    try: () => fs.mkdir(dirPath, { recursive: true }),
    catch: (e) => new Error(`Failed to create directory ${dirPath}: ${e}`),
  }).pipe(Effect.map(() => undefined))

const readJsonFile = <T>(filePath: string): Effect.Effect<T | null, Error> =>
  Effect.tryPromise({
    try: async () => {
      try {
        const content = await fs.readFile(filePath, 'utf-8')
        return JSON.parse(content) as T
      } catch {
        return null
      }
    },
    catch: (e) => new Error(`Failed to read ${filePath}: ${e}`),
  })

const writeJsonFile = <T>(
  filePath: string,
  data: T,
): Effect.Effect<void, Error> =>
  Effect.gen(function* () {
    const dir = path.dirname(filePath)
    yield* ensureDir(dir)
    yield* Effect.tryPromise({
      try: () => fs.writeFile(filePath, JSON.stringify(data, null, 2)),
      catch: (e) => new Error(`Failed to write ${filePath}: ${e}`),
    })
  })

// ============================================================================
// Hash Computation
// ============================================================================

export const computeHash = (content: string): string => {
  return crypto.createHash('sha256').update(content).digest('hex').slice(0, 16)
}

// ============================================================================
// Index Storage Operations
// ============================================================================

export interface IndexStorage {
  readonly rootPath: string
  readonly paths: ReturnType<typeof getIndexPaths>
}

export const createStorage = (rootPath: string): IndexStorage => ({
  rootPath: path.resolve(rootPath),
  paths: getIndexPaths(path.resolve(rootPath)),
})

export const initializeIndex = (
  storage: IndexStorage,
): Effect.Effect<void, Error> =>
  Effect.gen(function* () {
    yield* ensureDir(storage.paths.root)
    yield* ensureDir(storage.paths.parsed)
    yield* ensureDir(path.dirname(storage.paths.documents))

    // Create default config if it doesn't exist
    const existingConfig = yield* loadConfig(storage)
    if (!existingConfig) {
      const config: IndexConfig = {
        version: INDEX_VERSION,
        rootPath: storage.rootPath,
        include: ['**/*.md', '**/*.mdx'],
        exclude: ['**/node_modules/**', '**/.*/**'],
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      }
      yield* saveConfig(storage, config)
    }
  })

// ============================================================================
// Config Operations
// ============================================================================

export const loadConfig = (
  storage: IndexStorage,
): Effect.Effect<IndexConfig | null, Error> =>
  readJsonFile<IndexConfig>(storage.paths.config)

export const saveConfig = (
  storage: IndexStorage,
  config: IndexConfig,
): Effect.Effect<void, Error> =>
  writeJsonFile(storage.paths.config, {
    ...config,
    updatedAt: new Date().toISOString(),
  })

// ============================================================================
// Document Index Operations
// ============================================================================

export const loadDocumentIndex = (
  storage: IndexStorage,
): Effect.Effect<DocumentIndex | null, Error> =>
  readJsonFile<DocumentIndex>(storage.paths.documents)

export const saveDocumentIndex = (
  storage: IndexStorage,
  index: DocumentIndex,
): Effect.Effect<void, Error> => writeJsonFile(storage.paths.documents, index)

export const createEmptyDocumentIndex = (rootPath: string): DocumentIndex => ({
  version: INDEX_VERSION,
  rootPath,
  documents: {},
})

// ============================================================================
// Section Index Operations
// ============================================================================

export const loadSectionIndex = (
  storage: IndexStorage,
): Effect.Effect<SectionIndex | null, Error> =>
  readJsonFile<SectionIndex>(storage.paths.sections)

export const saveSectionIndex = (
  storage: IndexStorage,
  index: SectionIndex,
): Effect.Effect<void, Error> => writeJsonFile(storage.paths.sections, index)

export const createEmptySectionIndex = (): SectionIndex => ({
  version: INDEX_VERSION,
  sections: {},
  byHeading: {},
  byDocument: {},
})

// ============================================================================
// Link Index Operations
// ============================================================================

export const loadLinkIndex = (
  storage: IndexStorage,
): Effect.Effect<LinkIndex | null, Error> =>
  readJsonFile<LinkIndex>(storage.paths.links)

export const saveLinkIndex = (
  storage: IndexStorage,
  index: LinkIndex,
): Effect.Effect<void, Error> => writeJsonFile(storage.paths.links, index)

export const createEmptyLinkIndex = (): LinkIndex => ({
  version: INDEX_VERSION,
  forward: {},
  backward: {},
  broken: [],
})

// ============================================================================
// Index Existence Check
// ============================================================================

export const indexExists = (
  storage: IndexStorage,
): Effect.Effect<boolean, Error> =>
  Effect.tryPromise({
    try: async () => {
      try {
        await fs.access(storage.paths.config)
        return true
      } catch {
        return false
      }
    },
    catch: (e) => new Error(`Failed to check index existence: ${e}`),
  })

/**
 * Index data types for md-tldr
 */

// ============================================================================
// Configuration
// ============================================================================

export interface IndexConfig {
  readonly version: number
  readonly rootPath: string
  readonly include: readonly string[]
  readonly exclude: readonly string[]
  readonly createdAt: string
  readonly updatedAt: string
}

// ============================================================================
// Document Index
// ============================================================================

export interface DocumentIndex {
  readonly version: number
  readonly rootPath: string
  readonly documents: Record<string, DocumentEntry>
}

export interface DocumentEntry {
  readonly id: string
  readonly path: string
  readonly title: string
  readonly mtime: number
  readonly hash: string
  readonly tokenCount: number
  readonly sectionCount: number
}

// ============================================================================
// Section Index
// ============================================================================

export interface SectionIndex {
  readonly version: number
  readonly sections: Record<string, SectionEntry>
  readonly byHeading: Record<string, readonly string[]>
  readonly byDocument: Record<string, readonly string[]>
}

export interface SectionEntry {
  readonly id: string
  readonly documentId: string
  readonly documentPath: string
  readonly heading: string
  readonly level: number
  readonly startLine: number
  readonly endLine: number
  readonly tokenCount: number
  readonly hasCode: boolean
  readonly hasList: boolean
  readonly hasTable: boolean
}

// ============================================================================
// Link Index
// ============================================================================

export interface LinkIndex {
  readonly version: number
  readonly forward: Record<string, readonly string[]>
  readonly backward: Record<string, readonly string[]>
  readonly broken: readonly string[]
}

// ============================================================================
// Index Result
// ============================================================================

export interface IndexResult {
  readonly documentsIndexed: number
  readonly sectionsIndexed: number
  readonly linksIndexed: number
  readonly duration: number
  readonly errors: readonly IndexBuildError[]
}

export interface IndexBuildError {
  readonly path: string
  readonly message: string
}

// ============================================================================
// Index Paths
// ============================================================================

export const INDEX_DIR = '.md-tldr'
export const INDEX_VERSION = 1

export const getIndexPaths = (rootPath: string) => ({
  root: `${rootPath}/${INDEX_DIR}`,
  config: `${rootPath}/${INDEX_DIR}/config.json`,
  documents: `${rootPath}/${INDEX_DIR}/indexes/documents.json`,
  sections: `${rootPath}/${INDEX_DIR}/indexes/sections.json`,
  links: `${rootPath}/${INDEX_DIR}/indexes/links.json`,
  cache: `${rootPath}/${INDEX_DIR}/cache`,
  parsed: `${rootPath}/${INDEX_DIR}/cache/parsed`,
})

