  lines.push(`# ${summary.title}`)
  lines.push(`Path: ${summary.path}`)
  lines.push(
    `Tokens: ${totalTokens} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`,
  )
  lines.push('')

